#include <stdio.h>
#include <string.h>

int beautySum(const char *s) {
    int n = strlen(s);
    int total = 0;
    for (int i = 0; i < n; ++i) {
        int freq[26] = {0};
        for (int j = i; j < n; ++j) {
            freq[s[j] - 'a']++;
            int maxFreq = 0, minFreq = n; // n is an upper bound
            for (int k = 0; k < 26; ++k) {
                if (freq[k] > 0) {
                    if (freq[k] > maxFreq) maxFreq = freq[k];
                    if (freq[k] < minFreq) minFreq = freq[k];
                }
            }
            total += (maxFreq - minFreq);
        }
    }
    return total;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char s[501];
        scanf("%s", s);
        printf("%d\n", beautySum(s));
    }
    return 0;
}

