import sys

def beauty_sum(s: str) -> int:
    n = len(s)
    total = 0
    for i in range(n):
        freq = [0] * 26
        for j in range(i, n):
            freq[ord(s[j]) - 97] += 1
            max_f = 0
            min_f = n
            for f in freq:
                if f:
                    if f > max_f:
                        max_f = f
                    if f < min_f:
                        min_f = f
            total += max_f - min_f
    return total

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t + 1):
        s = data[i].strip()
        out.append(str(beauty_sum(s)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

